**TL;DR – the whole binding in one C‑source file**

```c
/*=====================================================================
 blocksci_lua.c  –  a tiny, self‑contained Lua binding for BlockSci
=====================================================================

  Build (Linux/ macOS, Lua 5.4, C++17)

     gcc -std=c++17 -shared -fPIC -O3 -I/usr/include/lua5.4 \
         -o blocksci.so blocksci_lua.c

  (On Windows replace “gcc … -shared -fPIC” with the appropriate
   MSVC command line.)

  The file contains:
    • a fake “Block” C++ class (replace with the real BlockSci header)
    • a thin iterator that walks ~800 M blocks (simulated here)
    • a reusable userdata that represents a block to Lua
    • an API that looks like the “apply‑per‑row” style of Polars/pandas

=====================================================================*/

extern "C" {
    #include <lua.h>
    #include <lauxlib.h>
    #include <lualib.h>
}
#include <cstdint>
#include <cstring>
#include <string>
#include <vector>
#include <chrono>
#include <random>

/* -----------------------------------------------------------------
   1️⃣  Fake BlockSci “Block” class – replace with the real one.
   ----------------------------------------------------------------- */
struct Block {
    uint64_t height;          // block height
    uint64_t timestamp;       // UNIX epoch seconds
    uint32_t tx_count;        // number of transactions in the block
    std::string hash;         // block hash (hex string)

    Block(uint64_t h, uint64_t ts, uint32_t tx, const std::string& hsh)
        : height(h), timestamp(ts), tx_count(tx), hash(hsh) {}
};

/* -----------------------------------------------------------------
   2️⃣  A very fast iterator that pretends to walk 800 M blocks.
   ----------------------------------------------------------------- */
class BlockIterator {
    uint64_t cur;                 // current height
    const uint64_t max;           // last height (inclusive)
    std::mt19937_64 rng;          // pseudo‑random data generator

public:
    explicit BlockIterator(uint64_t start = 0, uint64_t end = 800'000'000ULL)
        : cur(start), max(end), rng(start + 12345ULL) {}

    bool done() const { return cur > max; }

    Block next() {
        // In the real binding this would return a reference to the
        // actual Block object owned by BlockSci.  Here we fabricate
        // something plausible.
        uint64_t ts   = 1231006505ULL + cur * 600;          // 10‑min spacing
        uint32_t tx   = (rng() % 2000) + 1;                // 1‑2000 txs
        char buf[65];
        std::snprintf(buf, sizeof(buf), "%064llx", cur);
        std::string h(buf);
        ++cur;
        return Block(cur-1, ts, tx, h);
    }
};

/* -----------------------------------------------------------------
   3️⃣  The userdata that will be handed to Lua.
   ----------------------------------------------------------------- */
typedef struct {
    Block *blk;               // points to the *current* block
} BlockUdata;

/* Helper: push a (re‑used) Block userdata onto the stack.
   The userdata lives for the whole lifetime of the Lua state;
   we only replace its internal pointer each iteration.                */
static int push_block_userdata(lua_State *L, Block *blk) {
    // The userdata is stored in the registry under a fixed key.
    // If it does not exist yet we create it.
    lua_rawgetp(L, LUA_REGISTRYINDEX, (void*)push_block_userdata); // -> maybe udata
    if (lua_isnoneornil(L, -1)) {        // first call → create it
        lua_pop(L, 1);
        BlockUdata *ud = (BlockUdata*)lua_newuserdata(L, sizeof(BlockUdata));
        ud->blk = blk;                   // initialise
        // Set its metatable (shared for all block objects)
        luaL_getmetatable(L, "Blocksci.Block");
        lua_setmetatable(L, -2);
        // Store it in the registry for reuse
        lua_pushvalue(L, -1);
        lua_rawsetp(L, LUA_REGISTRYINDEX, (void*)push_block_userdata);
    } else {
        // Re‑use the existing userdata, just swap the internal pointer.
        BlockUdata *ud = (BlockUdata*)lua_touserdata(L, -1);
        ud->blk = blk;
    }
    // At this point the userdata is on top of the stack.
    return 1;
}

/* -----------------------------------------------------------------
   4️⃣  Block methods exposed to Lua (read‑only getters)
   ----------------------------------------------------------------- */
static int block_height(lua_State *L) {
    BlockUdata *ud = (BlockUdata*)luaL_checkudata(L, 1, "Blocksci.Block");
    lua_pushinteger(L, (lua_Integer)ud->blk->height);
    return 1;
}
static int block_timestamp(lua_State *L) {
    BlockUdata *ud = (BlockUdata*)luaL_checkudata(L, 1, "Blocksci.Block");
    lua_pushinteger(L, (lua_Integer)ud->blk->timestamp);
    return 1;
}
static int block_txcount(lua_State *L) {
    BlockUdata *ud = (BlockUdata*)luaL_checkudata(L, 1, "Blocksci.Block");
    lua_pushinteger(L, (lua_Integer)ud->blk->tx_count);
    return 1;
}
static int block_hash(lua_State *L) {
    BlockUdata *ud = (BlockUdata*)luaL_checkudata(L, 1, "Blocksci.Block");
    lua_pushlstring(L, ud->blk->hash.c_str(), ud->blk->hash.size());
    return 1;
}

/* __tostring for pretty printing (optional) */
static int block_tostring(lua_State *L) {
    BlockUdata *ud = (BlockUdata*)luaL_checkudata(L, 1, "Blocksci.Block");
    lua_pushfstring(L, "Block{height=%llu, hash=%s}",
        (unsigned long long)ud->blk->height,
        ud->blk->hash.c_str());
    return 1;
}

/* -----------------------------------------------------------------
   5️⃣  The hot‑path: iterate over all blocks and call a Lua callback.
   ----------------------------------------------------------------- */
static int lua_blocksci_iterate(lua_State *L) {
    // 1️⃣  Argument checking – a single callable is required.
    luaL_checktype(L, 1, LUA_TFUNCTION);
    // Keep a reference to the callback so that we can call it repeatedly.
    lua_pushvalue(L, 1);                     // +1 (callback)
    int cb_ref = luaL_ref(L, LUA_REGISTRYINDEX);

    // 2️⃣  Create the iterator (real code would acquire it from BlockSci).
    BlockIterator it;                        // starts at 0, ends at 800M

    // 3️⃣  Main loop – this is the *only* hot part.
    //    No heap allocation per iteration, only a few Lua API calls.
    for ( ; !it.done(); ++it ) {
        Block cur = it.next();               // real code would give a reference
        // Push the block userdata (re‑used) and the callback.
        push_block_userdata(L, &cur);        // stack: … block
        lua_rawgeti(L, LUA_REGISTRYINDEX, cb_ref); // stack: … block cb
        lua_insert(L, -2);                   // stack: … cb block
        // Call cb(block). 0 results, error handling via pcall.
        if (lua_pcall(L, 1, 0, 0) != LUA_OK) {
            // Propagate the Lua error (including stack trace) outwards.
            // The iterator stops early – the user gets the error.
            luaL_error(L, "callback error: %s", lua_tostring(L, -1));
        }
        // The callback succeeded – continue.
    }

    // 4️⃣  Cleanup: drop the reference to the callback.
    luaL_unref(L, LUA_REGISTRYINDEX, cb_ref);
    return 0;   // no values returned to Lua
}

/* -----------------------------------------------------------------
   6️⃣  Registration boiler‑plate
   ----------------------------------------------------------------- */
static const luaL_Reg block_methods[] = {
    {"height",    block_height},
    {"timestamp", block_timestamp},
    {"txcount",   block_txcount},
    {"hash",      block_hash},
    {NULL, NULL}
};

static const luaL_Reg blocksci_funcs[] = {
    {"iterate", lua_blocksci_iterate},
    {NULL, NULL}
};

extern "C" int luaopen_blocksci(lua_State *L) {
    // 1️⃣  Create the Block metatable.
    luaL_newmetatable(L, "Blocksci.Block");       // mt
    lua_pushvalue(L, -1);                         // mt mt
    lua_setfield(L, -2, "__index");               // mt.__index = mt
    // Register methods.
    luaL_setfuncs(L, block_methods, 0);
    // __tostring (nice for debugging)
    lua_pushcfunction(L, block_tostring);
    lua_setfield(L, -2, "__tostring");
    lua_pop(L, 1);                                // pop mt

    // 2️⃣  Create the module table.
    lua_newtable(L);                              // mod
    luaL_setfuncs(L, blocksci_funcs, 0);
    return 1;                                     // return mod
}
```

